31: public final class ShareRebalanceMetricsManager extends RebalanceMetricsManager {
32:     private final Sensor rebalanceSensor;
33:     public final MetricName rebalanceTotal;
34:     public final MetricName rebalanceRatePerHour;
35:     private long lastRebalanceEndMs = -1L;
36:     private long lastRebalanceStartMs = -1L;
37: 
38:     public ShareRebalanceMetricsManager(Metrics metrics) {
39:         super(CONSUMER_SHARE_METRIC_GROUP_PREFIX + COORDINATOR_METRICS_SUFFIX);
40: 
41:         rebalanceTotal = createMetric(metrics, "rebalance-total",
42:                 "The total number of rebalance events");
43:         rebalanceRatePerHour = createMetric(metrics, "rebalance-rate-per-hour",
44:                 "The number of rebalance events per hour");
45: 
46:         rebalanceSensor = metrics.sensor("rebalance-latency");
47:         rebalanceSensor.add(rebalanceTotal, new CumulativeCount());
48:         rebalanceSensor.add(rebalanceRatePerHour, new Rate(TimeUnit.HOURS, new WindowedCount()));
49:     }
50: 
51:     public void recordRebalanceStarted(long nowMs) {
52:         lastRebalanceStartMs = nowMs;
53:     }
